import React, { useState } from 'react';
import InventoryItem from '../components/InventoryItem';
import '../styles/inventory.css';

const RoomDetail = ({ room, user }) => {
    // Состояние для управления инвентарем внутри этого экрана
    const [items, setItems] = useState(room.inventory);
    const [note, setNote] = useState(room.notes);

    // Функция обновления количества
    const updateCount = (name, delta) => {
        setItems(items.map(item =>
            item.name === name
                ? { ...item, count: Math.max(0, item.count + delta) }
                : item
        ));
    };

    return (
        <div className="inventory-container">
            <div className="room-header-info">
                <h1 style={{margin: 0}}>НОМЕР {room.id}</h1>
                <p style={{fontSize: '12px', color: '#666'}}>Последняя чистка: {room.lastCleaned}</p>
            </div>

            <div className="product-list">
                {items.map((item, index) => (
                    <InventoryItem key={index} item={item} onUpdate={updateCount} />
                ))}
            </div>

            <textarea
                className="note-input"
                placeholder="Добавить заметку к номеру..."
                value={note}
                onChange={(e) => setNote(e.target.value)}
            />

            <div className="action-block">
                <button className="btn-check" onClick={() => alert('Сохранено: Проверено')}>
                    ВСЁ ОК / ПРОВЕРЕНО
                </button>
                <button className="btn-dnd" onClick={() => alert('Сохранено: DND/Отказ')}>
                    DND / ОТКАЗ
                </button>
            </div>
        </div>
    );
};

export default RoomDetail;
